sys_script_include.script:
var AROPCheckLibrary_ITSM = Class.create();
AROPCheckLibrary_ITSM.prototype = {
    initialize: function() {},
    _count: function(table, query) { var gr = new GlideRecord(table); if (query) gr.addEncodedQuery(query); gr.query(); return gr.getRowCount(); },
    _pct: function(num, den) { return den > 0 ? Math.round((num/den)*100) : 0; },
    CHK0000315: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var ga = new GlideAggregate('kb_knowledge');
    ga.addQuery('workflow_state', 'published');
    ga.addQuery('active', true);
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' published active KB articles';

    if (count >= 100) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' published KB articles. Sufficient content for Now Assist AI Search and knowledge-based deflection.'
        };
    } else if (count >= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' published KB articles (target: 100+). Now Assist AI Search deflection coverage will be limited — expand KB content for top incident categories.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + count + ' published KB articles. Insufficient content for meaningful Now Assist AI Search and knowledge deflection.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000315: ' + e.message };
        }
    },
    CHK0000316: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaPublished = new GlideAggregate('kb_knowledge');
    gaPublished.addQuery('workflow_state', 'published');
    gaPublished.addQuery('active', true);
    gaPublished.addAggregate('COUNT');
    gaPublished.query();
    var published = gaPublished.next() ? parseInt(gaPublished.getAggregate('COUNT')) : 0;

    if (published === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No published KB articles found',
            finding: 'No published KB articles found. KB staleness cannot be assessed.'
        };
    }

    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-365);

    var gaStale = new GlideAggregate('kb_knowledge');
    gaStale.addQuery('workflow_state', 'published');
    gaStale.addQuery('active', true);
    gaStale.addQuery('sys_updated_on', '<', cutoff.getValue());
    gaStale.addAggregate('COUNT');
    gaStale.query();
    var stale = gaStale.next() ? parseInt(gaStale.getAggregate('COUNT')) : 0;

    var pct = Math.round((stale / published) * 100);
    var actualValue = pct + '% stale (' + stale + ' of ' + published + ' articles over 12 months old)';

    if (pct <= 20) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of published KB articles are over 12 months old. KB content is current — Now Assist AI Search will return accurate, relevant results.'
        };
    } else if (pct <= 40) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: pct + '% of published KB articles are over 12 months old (target: ≤20%). Stale articles reduce Now Assist AI Search quality — establish a KB review cycle.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: pct + '% of published KB articles are over 12 months old. Majority of KB content is stale — Now Assist AI Search will return outdated information, degrading self-service quality.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000316: ' + e.message };
        }
    },
    CHK0000317: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaRetired = new GlideAggregate('kb_knowledge');
    gaRetired.addQuery('workflow_state', 'retired');
    gaRetired.addAggregate('COUNT');
    gaRetired.query();
    var retired = gaRetired.next() ? parseInt(gaRetired.getAggregate('COUNT')) : 0;

    var gaTotal = new GlideAggregate('kb_knowledge');
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    var pct = total > 0 ? Math.round((retired / total) * 100) : 0;
    var actualValue = pct + '% retired (' + retired + ' of ' + total + ' articles)';

    // Informational check — active retirement indicates good KB hygiene
    return {
        status: 'ready',
        actualValue: actualValue,
        finding: 'KB retirement rate: ' + pct + '% (' + retired + ' retired of ' + total + ' total). Active article retirement is a positive signal — it indicates KB governance is in place to keep Now Assist AI Search content current and accurate.'
    };
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000317: ' + e.message };
        }
    },
    CHK0000318: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaPublished = new GlideAggregate('kb_knowledge');
    gaPublished.addQuery('workflow_state', 'published');
    gaPublished.addQuery('active', true);
    gaPublished.addAggregate('COUNT');
    gaPublished.query();
    var published = gaPublished.next() ? parseInt(gaPublished.getAggregate('COUNT')) : 0;

    if (published === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No published KB articles found',
            finding: 'No published KB articles found. Categorization completeness cannot be assessed.'
        };
    }

    var gaCat = new GlideAggregate('kb_knowledge');
    gaCat.addQuery('workflow_state', 'published');
    gaCat.addQuery('active', true);
    gaCat.addQuery('kb_category', '!=', '');
    gaCat.addAggregate('COUNT');
    gaCat.query();
    var withCat = gaCat.next() ? parseInt(gaCat.getAggregate('COUNT')) : 0;

    var pct = Math.round((withCat / published) * 100);
    var actualValue = pct + '% categorized (' + withCat + ' of ' + published + ' articles have category)';

    if (pct >= 95) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of published KB articles have a category. Now Assist AI Search can accurately scope and filter results by category.'
        };
    } else if (pct >= 80) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of published KB articles are categorized (target: 95%+). Uncategorized articles reduce Now Assist AI Search filtering accuracy.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of published KB articles have a category. Insufficient categorization — Now Assist AI Search cannot accurately scope results without category data.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000318: ' + e.message };
        }
    },
    CHK0000319: function() {
        try {
            return (function(checkDef, dateFilter) {
    var gaTotal = new GlideAggregate("kb_knowledge");
    gaTotal.addQuery("workflow_state", "published");
    gaTotal.addQuery("active", true);
    gaTotal.addAggregate("COUNT");
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate("COUNT")) : 0;

    if (total === 0) {
        return { status: "not_applicable", actualValue: "No published KB articles found",
            finding: "No published KB articles found. Language consistency cannot be assessed." };
    }

    // Count articles with language explicitly set to a non-English value.
    // Articles with NULL/empty language field are treated as English --
    // most orgs never set this field even for English content.
    var gaNonEng = new GlideAggregate("kb_knowledge");
    gaNonEng.addQuery("workflow_state", "published");
    gaNonEng.addQuery("active", true);
    gaNonEng.addNotNullQuery("language");
    gaNonEng.addQuery("language", "NOT IN", "en,en_US,en_us,english,English");
    gaNonEng.addAggregate("COUNT");
    gaNonEng.query();
    var nonEng = gaNonEng.next() ? parseInt(gaNonEng.getAggregate("COUNT")) : 0;

    // Count articles with null language (treated as English)
    var gaNull = new GlideAggregate("kb_knowledge");
    gaNull.addQuery("workflow_state", "published");
    gaNull.addQuery("active", true);
    gaNull.addNullQuery("language");
    gaNull.addAggregate("COUNT");
    gaNull.query();
    var nullLang = gaNull.next() ? parseInt(gaNull.getAggregate("COUNT")) : 0;

    var pct = Math.round((nonEng / total) * 100);
    var actualValue = pct + "% explicitly non-English articles (" + nonEng + " of " + total + ")" +
        (nullLang > 0 ? " | " + nullLang + " with no language set (treated as English)" : "");

    if (pct <= 10) {
        return { status: "ready", actualValue: actualValue,
            finding: "Only " + pct + "% of published articles are explicitly non-English. Now Assist AI Search has primarily English content." };
    } else if (pct <= 30) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: pct + "% of published articles are non-English (target: ≤10%). Confirm multilingual Now Assist language pack licensing for non-English content coverage." };
    } else {
        return { status: "not_ready", actualValue: actualValue,
            finding: pct + "% of published articles are non-English. High non-English rate without confirmed multilingual licensing will result in poor Now Assist AI Search accuracy for those articles." };
    }
})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000319: ' + e.message };
        }
    },
    CHK0000320: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaTotal = new GlideAggregate('kb_knowledge');
    gaTotal.addQuery('workflow_state', 'published');
    gaTotal.addQuery('active', true);
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No published KB articles found',
            finding: 'No published KB articles found. Empty text field check cannot be assessed.'
        };
    }

    var gaEmpty = new GlideAggregate('kb_knowledge');
    gaEmpty.addQuery('workflow_state', 'published');
    gaEmpty.addQuery('active', true);
    gaEmpty.addQuery('text', '');
    gaEmpty.addAggregate('COUNT');
    gaEmpty.query();
    var empty = gaEmpty.next() ? parseInt(gaEmpty.getAggregate('COUNT')) : 0;

    var pct = Math.round((empty / total) * 100);
    var actualValue = empty + ' of ' + total + ' published articles have empty text body (' + pct + '%)';

    if (empty === 0) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'All published KB articles have body content. Now Assist AI Search has substantive content to index and surface as self-service answers.'
        };
    } else if (pct <= 5) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: empty + ' published KB articles have empty body text (' + pct + '%). Empty articles degrade Now Assist AI Search quality — populate or retire these articles.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: empty + ' published KB articles (' + pct + '%) have no body content. Now Assist AI Search will return empty or useless results for these articles.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000320: ' + e.message };
        }
    },
    CHK0000321: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaTotal = new GlideAggregate('kb_knowledge');
    gaTotal.addQuery('workflow_state', 'published');
    gaTotal.addQuery('active', true);
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    var gaLabeled = new GlideAggregate('label_entry');
    gaLabeled.addQuery('table', 'kb_knowledge');
    gaLabeled.addAggregate('COUNT');
    gaLabeled.query();
    var labelCount = gaLabeled.next() ? parseInt(gaLabeled.getAggregate('COUNT')) : 0;

    var actualValue = labelCount + ' label entries across ' + total + ' published articles';

    if (labelCount > 0) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: labelCount + ' KB article label entries found. Now Assist AI Search can filter results by label to scope results by audience and service context.'
        };
    } else {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'No KB article labels found. Labels allow Now Assist AI Search to filter results by audience and service context — without them AI Search returns unfiltered results to all users.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000321: ' + e.message };
        }
    },
    CHK0000322: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaTotal = new GlideAggregate('kb_knowledge');
    gaTotal.addQuery('workflow_state', 'published');
    gaTotal.addQuery('active', true);
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No published KB articles found',
            finding: 'No published KB articles found. URL content check cannot be assessed.'
        };
    }

    var gaURL = new GlideAggregate('kb_knowledge');
    gaURL.addQuery('workflow_state', 'published');
    gaURL.addQuery('active', true);
    gaURL.addQuery('text', 'CONTAINS', 'https://');
    gaURL.addAggregate('COUNT');
    gaURL.query();
    var withUrl = gaURL.next() ? parseInt(gaURL.getAggregate('COUNT')) : 0;

    var pct = Math.round((withUrl / total) * 100);
    var actualValue = withUrl + ' of ' + total + ' published articles contain raw URLs (' + pct + '%)';

    if (pct <= 20) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of articles contain raw URLs. Now Assist AI Search has predominantly self-contained content that can be summarized without link dependencies.'
        };
    } else if (pct <= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: pct + '% of published articles contain raw URLs (target: ≤20%). Now Assist cannot follow hyperlinks — URL-dependent content will produce incomplete AI summaries.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: pct + '% of published articles rely on raw URLs. Now Assist AI Search cannot follow links — the majority of KB content will produce incomplete AI summaries and poor self-service answers.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000322: ' + e.message };
        }
    },
    CHK0000323: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var gaTables = new GlideAggregate('kb_knowledge');
    gaTables.addQuery('workflow_state', 'published');
    gaTables.addQuery('active', true);
    gaTables.addQuery('text', 'CONTAINS', '<table');
    gaTables.addAggregate('COUNT');
    gaTables.query();
    var tables = gaTables.next() ? parseInt(gaTables.getAggregate('COUNT')) : 0;

    var gaImgs = new GlideAggregate('kb_knowledge');
    gaImgs.addQuery('workflow_state', 'published');
    gaImgs.addQuery('active', true);
    gaImgs.addQuery('text', 'CONTAINS', '<img');
    gaImgs.addAggregate('COUNT');
    gaImgs.query();
    var imgs = gaImgs.next() ? parseInt(gaImgs.getAggregate('COUNT')) : 0;

    var total = tables + imgs;
    var actualValue = 'Articles with HTML tables: ' + tables + ' | Articles with images: ' + imgs + ' | Total AI suitability issues: ' + total;

    if (total === 0) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'No AI suitability issues found. KB articles are structured for clean Now Assist AI summarization without HTML tables or images.'
        };
    } else if (total < 100) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: total + ' articles have AI suitability issues (HTML tables: ' + tables + ', images: ' + imgs + '). Now Assist flattens HTML tables and ignores images — convert to prose for better AI summarization quality.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: total + ' articles have AI suitability issues. High volume of table-heavy and image-dependent KB content will significantly degrade Now Assist AI summarization quality across the knowledge base.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000323: ' + e.message };
        }
    },
    CHK0000324: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('incident');
    gaTotal.addQuery('state', 'IN', '6,7');
    gaTotal.addQuery('closed_at', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No closed incidents in last 12 months',
            finding: 'No closed incidents found in the last 12 months. Resolution note coverage cannot be assessed.'
        };
    }

    var gaMissing = new GlideAggregate('incident');
    gaMissing.addQuery('state', 'IN', '6,7');
    gaMissing.addQuery('closed_at', '>=', cutoff.getValue());
    gaMissing.addQuery('close_notes', '');
    gaMissing.addAggregate('COUNT');
    gaMissing.query();
    var missing = gaMissing.next() ? parseInt(gaMissing.getAggregate('COUNT')) : 0;

    var populated = total - missing;
    var pct = Math.round((populated / total) * 100);
    var actualValue = pct + '% of closed incidents have close_notes (last 12 months, ' + populated + '/' + total + ')';

    if (pct >= 95) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of closed incidents have resolution notes. Now Assist ITSM has strong resolution context for AI case summarization and similar incident matching.'
        };
    } else if (pct >= 80) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have resolution notes (target: 95%). Now Assist ITSM summarization quality will be reduced for incidents missing resolution context.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have resolution notes. Critical gap — Now Assist ITSM cannot generate meaningful case summaries without resolution context.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000324: ' + e.message };
        }
    },
    CHK0000325: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var total = new GlideAggregate('incident');
    total.addQuery('state', 7);
    total.addQuery('closed_at', '>=', cutoff.getValue());
    total.addAggregate('COUNT');
    total.query();
    var totalCount = total.next() ? parseInt(total.getAggregate('COUNT')) : 0;

    if (totalCount === 0) {
        return {
            status: 'not_ready',
            actualValue: 'No closed incidents found in last 12 months',
            finding: 'No closed incident data available to assess classification signal for Predictive Intelligence training.'
        };
    }

    var pathA = new GlideAggregate('incident');
    pathA.addQuery('state', 7);
    pathA.addQuery('closed_at', '>=', cutoff.getValue());
    pathA.addQuery('category', '!=', '');
    pathA.addQuery('category', '!=', 'Inquiry/Help');
    pathA.addQuery('subcategory', '!=', '');
    pathA.addAggregate('COUNT');
    pathA.query();
    var pathACount = pathA.next() ? parseInt(pathA.getAggregate('COUNT')) : 0;
    var pathAPct = Math.round((pathACount / totalCount) * 100);

    var pathB = new GlideAggregate('incident');
    pathB.addQuery('state', 7);
    pathB.addQuery('closed_at', '>=', cutoff.getValue());
    pathB.addQuery('business_service', '!=', '');
    pathB.addQuery('service_offering', '!=', '');
    pathB.addQuery('cmdb_ci', '!=', '');
    pathB.addAggregate('COUNT');
    pathB.query();
    var pathBCount = pathB.next() ? parseInt(pathB.getAggregate('COUNT')) : 0;
    var pathBPct = Math.round((pathBCount / totalCount) * 100);

    var actualValue = 'Total: ' + totalCount + ' | Category+Subcategory: ' + pathAPct + '% | Service+SO+CI: ' + pathBPct + '%';
    var bestPct = Math.max(pathAPct, pathBPct);

    if (bestPct >= 80) {
        return { status: 'ready', actualValue: actualValue,
            finding: 'Sufficient classification signal for Predictive Intelligence training. Best path at ' + bestPct + '%.' };
    } else if (bestPct >= 50) {
        return { status: 'needs_attention', actualValue: actualValue,
            finding: 'Classification signal partial at ' + bestPct + '% (target: 80%). Predictive Intelligence routing accuracy will be reduced.' };
    } else {
        return { status: 'not_ready', actualValue: actualValue,
            finding: 'Insufficient classification signal. Category+Subcategory: ' + pathAPct + '%, Service+SO+CI: ' + pathBPct + '%. Both below 50% — Predictive Intelligence will produce unreliable routing recommendations.' };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000325: ' + e.message };
        }
    },
    CHK0000326: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('incident');
    gaTotal.addQuery('state', 'IN', '6,7');
    gaTotal.addQuery('closed_at', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No closed incidents in last 12 months',
            finding: 'No closed incidents found in the last 12 months. Assignment group population cannot be assessed.'
        };
    }

    var gaMissing = new GlideAggregate('incident');
    gaMissing.addQuery('state', 'IN', '6,7');
    gaMissing.addQuery('closed_at', '>=', cutoff.getValue());
    gaMissing.addQuery('assignment_group', '');
    gaMissing.addAggregate('COUNT');
    gaMissing.query();
    var missing = gaMissing.next() ? parseInt(gaMissing.getAggregate('COUNT')) : 0;

    var populated = total - missing;
    var pct = Math.round((populated / total) * 100);
    var actualValue = pct + '% of closed incidents have assignment group (last 12 months, ' + populated + '/' + total + ')';

    if (pct >= 95) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of closed incidents have an assignment group. Now Assist ITSM AI routing has strong historical assignment data for routing recommendations.'
        };
    } else if (pct >= 80) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have an assignment group (target: 95%). Now Assist AI routing recommendations will have gaps for unassigned incidents.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have an assignment group. Now Assist ITSM AI routing cannot learn effective assignment patterns without this data.'
        };
    }
}))();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000326: ' + e.message };
        }
    },
    CHK0000327: function() {
        try {
            return ((function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('incident');
    gaTotal.addQuery('state', 'IN', '6,7');
    gaTotal.addQuery('closed_at', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No closed incidents in last 12 months',
            finding: 'No closed incidents found in the last 12 months. Close code consistency cannot be assessed.'
        };
    }

    var gaWithCode = new GlideAggregate('incident');
    gaWithCode.addQuery('state', 'IN', '6,7');
    gaWithCode.addQuery('closed_at', '>=', cutoff.getValue());
    gaWithCode.addQuery('close_code', '!=', '');
    gaWithCode.addAggregate('COUNT');
    gaWithCode.query();
